import React, { useState, useRef, useEffect, useImperativeHandle, forwardRef } from 'react';
import { Send, Loader2, Paperclip, X, Brain } from 'lucide-react';

interface ChatInputProps {
  onSendMessage: (content: string, file: File | null, isDeepThink: boolean) => void;
  isLoading: boolean;
  prefilledText?: string;
  onClearPrefill?: () => void;
  statusMessage?: string;
}

export interface ChatInputHandle {
  focus: () => void;
}

export const ChatInput = forwardRef<ChatInputHandle, ChatInputProps>(({ 
  onSendMessage, 
  isLoading, 
  prefilledText, 
  onClearPrefill,
  statusMessage
}, ref) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isDeepThink, setIsDeepThink] = useState(false);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useImperativeHandle(ref, () => ({
    focus: () => {
      textareaRef.current?.focus();
    }
  }));

  useEffect(() => {
    if (prefilledText) {
      setInput(prefilledText);
      textareaRef.current?.focus();
      if (onClearPrefill) onClearPrefill();
    }
  }, [prefilledText, onClearPrefill]);

  const handleSubmit = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() && !selectedFile) return;

    onSendMessage(input, selectedFile, isDeepThink);
    setInput('');
    // Note: We don't clear selectedFile here automatically if we want to persist it,
    // but usually in chat interfaces the file is sent once. 
    // The prompt says "use the same uri in the chat... until another uri doesn't come".
    // This logic is better handled in App.tsx state, but visually we remove it from input after send.
    setSelectedFile(null); 
    if (fileInputRef.current) fileInputRef.current.value = '';

    // Reset height
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    // Alt+S to send
    if (e.altKey && e.key.toLowerCase() === 's') {
      e.preventDefault();
      handleSubmit();
      return;
    }

    // Alt+A to attach
    if (e.altKey && e.key.toLowerCase() === 'a') {
      e.preventDefault();
      fileInputRef.current?.click();
      return;
    }

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [input]);

  const isSendDisabled = (!input.trim() && !selectedFile) || isLoading;

  return (
    <div className="w-full bg-surface border-t border-gray-700/50 px-4 pt-4 pb-6">

      {/* Accessibility Alert */}
      <div role="alert" aria-live="polite" className="sr-only">
        {statusMessage}
      </div>

      <div className="max-w-3xl mx-auto relative flex flex-col gap-2">

        {/* Selected File Display */}
        {selectedFile && (
           <div className="flex items-center gap-2 bg-background border border-gray-700 rounded-lg px-3 py-2 w-fit mb-1 animate-in slide-in-from-bottom-2">
             <div className="flex flex-col">
                <p className="text-xs text-primary font-medium">Attached File</p>
                <p className="text-sm text-gray-200 truncate max-w-[200px]">{selectedFile.name}</p>
             </div>
             <button 
               onClick={() => {
                 setSelectedFile(null);
                 if (fileInputRef.current) fileInputRef.current.value = '';
               }}
               className="ml-2 p-1 hover:bg-gray-700 rounded-full text-gray-400 hover:text-white transition-colors"
               aria-label="Remove file"
             >
               <X size={14} />
             </button>
           </div>
        )}

        <form onSubmit={handleSubmit} className="relative flex items-end gap-2 bg-background p-2 rounded-xl border border-gray-700/50 focus-within:border-primary/50 focus-within:ring-1 focus-within:ring-primary/20 transition-all shadow-lg">
          <textarea
            ref={textareaRef}
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Ask AI assistant anything... (Alt+S to send)"
            className="w-full bg-transparent text-gray-100 placeholder-gray-500 resize-none outline-none py-3 px-3 min-h-[50px] max-h-[200px] text-sm md:text-base scrollbar-hide"
            rows={1}
          />

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleFileChange}
            className="hidden"
            // Accept broad range as requested: "videos, audios, images, documents and codes"
            accept="image/*,video/*,audio/*,.pdf,.txt,.md,.js,.ts,.py,.java,.c,.cpp,.html,.css,.json,.csv" 
          />
        </form>

        {/* Toolbar Below Input */}
        <div className="flex items-center justify-between px-1">
          <div className="flex items-center gap-3">
             {/* Add Files Button */}
             <button
               type="button"
               onClick={() => fileInputRef.current?.click()}
               className="flex items-center gap-2 text-xs font-medium text-gray-400 hover:text-white transition-colors py-1 px-2 rounded hover:bg-gray-800"
               title="Add Files (Alt+A)"
             >
               <Paperclip size={14} />
               <span>Add Files</span>
             </button>

             {/* Deep Think Toggle */}
             <button
               type="button"
               onClick={() => setIsDeepThink(!isDeepThink)}
               className={`flex items-center gap-2 text-xs font-medium transition-all py-1 px-2 rounded border ${isDeepThink ? 'bg-indigo-900/30 border-indigo-500/50 text-indigo-300' : 'bg-transparent border-transparent text-gray-400 hover:bg-gray-800 hover:text-white'}`}
               title={isDeepThink ? "Disable Deep Thinking Mode" : "Enable Deep Thinking Mode"}
             >
               <Brain size={14} />
               <span>Deep Think</span>
               <div className={`w-6 h-3 rounded-full relative transition-colors ${isDeepThink ? 'bg-indigo-500' : 'bg-gray-600'}`}>
                 <div className={`absolute top-0.5 w-2 h-2 rounded-full bg-white transition-transform ${isDeepThink ? 'left-3.5' : 'left-0.5'}`} />
               </div>
             </button>
          </div>

          <button
            onClick={() => handleSubmit()}
            disabled={isSendDisabled}
            aria-label="Send prompt"
            className={`
              p-2.5 rounded-lg flex-shrink-0
              transition-all duration-200 flex items-center gap-2
              ${isSendDisabled 
                ? 'bg-gray-800 text-gray-500 cursor-not-allowed' 
                : 'bg-primary text-white hover:bg-blue-600 shadow-lg shadow-blue-500/20 active:scale-95'}
            `}
          >
            {isLoading ? (
              <Loader2 size={18} className="animate-spin" />
            ) : (
              <Send size={18} />
            )}
            <span className="sr-only">Send</span>
          </button>
        </div>

      </div>
    </div>
  );
});

